const data = $input.first().json;
const today = new Date().toISOString().split('T')[0];

// Sum total spend from LiteLLM logs
let totalSpend = 0;
const logs = Array.isArray(data) ? data : (data.data || []);
logs.forEach(log => { totalSpend += parseFloat(log.spend || log.cost || 0); });

// Cost threshold classification (CLAUDE.md Section 10)
let status, threshold, action;
if (totalSpend > 5) {
  status = '🔴 CRITICAL';
  threshold = '>$5/day';
  action = 'KILLSWITCH — Switch to Ollama only immediately';
} else if (totalSpend > 3) {
  status = '🟠 HIGH';
  threshold = '>$3/day';
  action = 'Switch ALL tasks to Gemini Flash';
} else if (totalSpend > 1) {
  status = '🟡 WARNING';
  threshold = '>$1/day';
  action = 'Switch thinking tasks to Gemini Pro';
} else {
  status = '✅ NORMAL';
  threshold = 'Under $1/day';
  action = 'None';
}

const requiresAlert = totalSpend > 1;

return [{ json: { date: today, totalSpend: totalSpend.toFixed(4), status, threshold, action, requiresAlert, logCount: logs.length } }];

